import pytest, requests
from tests.fixtures import patient_auth_token, base_url, existing_active_consent

def test_access_denied_after_revocation(patient_auth_token, base_url, existing_active_consent):
    resource_id, subject_id = existing_active_consent
    headers = {"Authorization": f"Bearer {patient_auth_token}",
               "Content-Type": "application/fhir+json"}
    revoke_payload = {
        "resourceType": "Consent",
        "id": resource_id,
        "status": "inactive",
        "scope": {"coding": [{"code": "patient-privacy"}]},
        "category": [{"coding": [{"code": "59284-0"}]}],
        "provision": {"type": "deny"}
    }
    revoke_resp = requests.put(
        f"{base_url}/Consent/{resource_id}", json=revoke_payload, headers=headers
    )
    assert revoke_resp.status_code == 200, f"Revoke failed: {revoke_resp.text}"
    access_resp = requests.get(
        f"{base_url}/Patient/{subject_id}/$everything", headers=headers
    )
    assert access_resp.status_code in (401, 403), (
        f"Expected 401/403 after revocation, got {access_resp.status_code}"
    )
    body = access_resp.json()
    assert body.get("resourceType") == "OperationOutcome"

import pytest, requests, time
from unittest.mock import patch
from tests.fixtures import patient_auth_token, base_url, existing_active_consent
from tests.helpers import simulate_elapsed_time

SLA_SECONDS = 900

def test_access_denied_at_exactly_15_minute_boundary(
    patient_auth_token, base_url, existing_active_consent
):
    resource_id, subject_id = existing_active_consent
    headers = {"Authorization": f"Bearer {patient_auth_token}",
               "Content-Type": "application/fhir+json"}
    revoke_payload = {
        "resourceType": "Consent", "id": resource_id,
        "status": "inactive",
        "scope": {"coding": [{"code": "patient-privacy"}]},
        "category": [{"coding": [{"code": "59284-0"}]}],
        "provision": {"type": "deny"}
    }
    rev = requests.put(
        f"{base_url}/Consent/{resource_id}", json=revoke_payload, headers=headers
    )
    assert rev.status_code == 200
    with simulate_elapsed_time(SLA_SECONDS):
        resp_at_boundary = requests.get(
            f"{base_url}/Patient/{subject_id}/$everything", headers=headers
        )
    assert resp_at_boundary.status_code in (401, 403), (
        f"At T+{SLA_SECONDS}s expected denial, got {resp_at_boundary.status_code}"
    )

import pytest, requests
from tests.fixtures import (
    patient_auth_token_permit, patient_auth_token_deny,
    base_url, patient_id_permit, patient_id_deny
)

def test_consent_decision_table_permit_vs_deny(
    base_url,
    patient_auth_token_permit, patient_id_permit,
    patient_auth_token_deny, patient_id_deny
):
    hdrs_permit = {"Authorization": f"Bearer {patient_auth_token_permit}"}
    hdrs_deny = {"Authorization": f"Bearer {patient_auth_token_deny}"}
    resp_permit = requests.get(
        f"{base_url}/Patient/{patient_id_permit}/$everything", headers=hdrs_permit
    )
    resp_deny = requests.get(
        f"{base_url}/Patient/{patient_id_deny}/$everything", headers=hdrs_deny
    )
    assert resp_permit.status_code == 200, (
        f"Permit patient expected 200, got {resp_permit.status_code}"
    )
    assert resp_deny.status_code in (401, 403), (
        f"Deny patient expected 401/403, got {resp_deny.status_code}"
    )
    deny_body = resp_deny.json()
    assert deny_body.get("resourceType") == "OperationOutcome"
